import 'dart:io'; import 'package:cached_network_image/cached_network_image.dart'; import 'package:flutter/material.dart';
class EvidenceImageGrid extends StatelessWidget{const EvidenceImageGrid({super.key,required this.images,this.networkImages=const[],required this.onAddImage,required this.onRemoveLocalImage,this.onRemoveNetworkImage,this.isUploading=false,this.maxImages=5}); final List<File> images; final List<String> networkImages; final VoidCallback onAddImage; final ValueChanged<int> onRemoveLocalImage; final ValueChanged<int>? onRemoveNetworkImage; final bool isUploading; final int maxImages; int get total=>images.length+networkImages.length; @override Widget build(BuildContext context){final canAdd=total<maxImages; if(total==0)return InkWell(onTap:onAddImage,child:Container(height:130,alignment:Alignment.center,decoration:BoxDecoration(border:Border.all(color:Theme.of(context).colorScheme.outlineVariant),borderRadius:BorderRadius.circular(12)),child:const Column(mainAxisSize:MainAxisSize.min,children:[Icon(Icons.add_photo_alternate_outlined),Text('Add Evidence')]))); final itemCount=total+(canAdd?1:0); return Stack(children:[GridView.builder(shrinkWrap:true,physics:const NeverScrollableScrollPhysics(),itemCount:itemCount,gridDelegate:const SliverGridDelegateWithFixedCrossAxisCount(crossAxisCount:3,crossAxisSpacing:8,mainAxisSpacing:8),itemBuilder:(_,i){if(canAdd&&i==itemCount-1)return InkWell(onTap:onAddImage,child:const Card(child:Icon(Icons.add))); if(i<networkImages.length)return _Tile(child:CachedNetworkImage(imageUrl:networkImages[i],fit:BoxFit.cover),onRemove:onRemoveNetworkImage==null?null:()=>onRemoveNetworkImage!(i)); final local=i-networkImages.length; return _Tile(child:Image.file(images[local],fit:BoxFit.cover),onRemove:()=>onRemoveLocalImage(local));}), if(isUploading) const Positioned.fill(child:ColoredBox(color:Color(0x66000000),child:Center(child:CircularProgressIndicator())))]);}}
class _Tile extends StatelessWidget{final Widget child; final VoidCallback? onRemove; const _Tile({required this.child,this.onRemove}); @override Widget build(BuildContext context)=>ClipRRect(borderRadius:BorderRadius.circular(12),child:Stack(fit:StackFit.expand,children:[child,Positioned(right:4,top:4,child:IconButton.filledTonal(onPressed:onRemove,icon:const Icon(Icons.close,size:16)))]));}
